<?php
namespace Tests\Unit\Domain\Combat;use App\Domain\Combat\CombatDamageMitigationService;use App\Domain\Combat\Data\CombatMitigationConfig;use PHPUnit\Framework\TestCase;
final class CombatDamageMitigationServiceTest extends TestCase{private function result($incoming,$attack,$defense,$absorb=0,$config=null){return(new CombatDamageMitigationService())->mitigate($incoming,$attack,$defense,$absorb,$config?:CombatMitigationConfig::defaults());}public function test_defense_compares_attack_and_defense_without_early_damage_rounding(){$a=$this->result(10,10,5);$b=$this->result(10,10,6);$this->assertSame(3333,$a->rawDefenseReductionBasisPoints());$this->assertSame(7,$a->finalDamage());$this->assertSame(3750,$b->rawDefenseReductionBasisPoints());$this->assertSame(6,$b->finalDamage());}public function test_absorb_applies_after_defense(){$r=$this->result(500,500,500,6000);$this->assertEquals(250.0,$r->damageAfterDefense());$this->assertEquals(100.0,$r->damageAfterAbsorb());$this->assertSame(100,$r->finalDamage());}public function test_individual_and_combined_caps_and_minimum(){$r=$this->result(100,1,100000,9000,new CombatMitigationConfig(7000,7000,9000,1));$this->assertSame(7000,$r->appliedDefenseReductionBasisPoints());$this->assertSame(7000,$r->appliedAbsorbBasisPoints());$this->assertSame(10,$r->finalDamage());$this->assertSame(5,$this->result(1,10,0,0,new CombatMitigationConfig(7000,7000,9000,5))->finalDamage());}public function test_zero_and_invalid_values_are_explicit(){$this->assertSame(1,$this->result(0,0,0)->finalDamage());$this->expectException(\InvalidArgumentException::class);$this->result(10,10,-1);}}
